// scripts/generate-cli-reference.mjs
//
// CLI reference generator + drift gate (W1-T48).
//
// `rmd --help` / `rmd <cmd> --help` already render from ONE source of truth — the COMMANDS
// registry in src/run-task.ts (W1-T47) — so the two help surfaces can't drift from each other.
// This script closes the remaining gap: a human-browsable docs/cli-reference.md that ALSO
// renders from that same COMMANDS array, so the committed doc can't drift from the registry
// (and therefore can't drift from what the binary actually prints/dispatches) either.
//
// The generated file is content-only (no timestamp, no invocation-environment data) so it is
// byte-stable across runs when COMMANDS hasn't changed -- that is what makes `--check` a
// meaningful staleness gate rather than a permanent false positive (same discipline as
// scripts/generate-learnings-index.mjs, W1-T33).
//
// Usage:
//   npm run cli-reference          # regenerate docs/cli-reference.md
//   npm run cli-reference:check    # exit 1 if the committed file is stale (run in `npm test`,
//                                  # so CI's `ci` job -- already a REQUIRED check -- byte-compares
//                                  # it on every PR; see test/cli-reference.test.ts)
//
// Run directly with `tsx` (not plain `node`): COMMANDS lives in a .ts module, and only tsx's
// loader can import that from this script.

import { readFileSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { parseArgs } from "node:util";
import { pathToFileURL } from "node:url";
import { COMMANDS, USAGE } from "../src/run-task.ts";

const DEFAULT_OUT = join("docs", "cli-reference.md");

/** Split one registry usage line into its invocation shape and trailing "# description" prose. */
export function splitUsage(usage) {
  const parts = usage.split(/\s{2,}#\s?/);
  const invocation = parts[0].trimEnd();
  const description = parts.slice(1).join(" # ").trim();
  return { invocation, description };
}

/**
 * Split a rendered reference doc into { commandName -> its "### `rmd <name>` ... " block }, keyed
 * by the section heading -- used only to NAME which command(s) drifted in a --check failure
 * (MASTER-PLAN §12A: "stale generated docs = RED, naming the drifted command"), never to decide
 * pass/fail (that is a plain whole-file byte comparison, same discipline as
 * scripts/generate-learnings-index.mjs).
 */
export function extractCommandSections(text) {
  const re = /^### `rmd ([^`]+)`$/gm;
  const matches = [...text.matchAll(re)];
  const sections = {};
  for (let i = 0; i < matches.length; i++) {
    const name = matches[i][1];
    const start = matches[i].index;
    const end = i + 1 < matches.length ? matches[i + 1].index : text.length;
    sections[name] = text.slice(start, end);
  }
  return sections;
}

/** Command names whose rendered section differs (or is missing/added) between two reference docs. */
export function driftedCommandNames(committed, fresh) {
  const committedSections = extractCommandSections(committed);
  const freshSections = extractCommandSections(fresh);
  const names = new Set([...Object.keys(committedSections), ...Object.keys(freshSections)]);
  return [...names].filter((name) => committedSections[name] !== freshSections[name]).sort();
}

/** Render the full reference doc from COMMANDS -- pure function of the registry, no I/O. */
export function renderReference(commands, usage) {
  const lines = [];
  lines.push("<!--");
  lines.push("AUTO-GENERATED -- DO NOT EDIT BY HAND.");
  lines.push("Generated by scripts/generate-cli-reference.mjs from the COMMANDS registry in");
  lines.push("src/run-task.ts -- the SAME source `rmd --help` / `rmd <cmd> --help` render from");
  lines.push("(W1-T47). Run `npm run cli-reference` to regenerate after changing COMMANDS.");
  lines.push("`npm run cli-reference:check` (part of `npm test`, W1-T48) fails CI if this file");
  lines.push("has drifted from a fresh regeneration.");
  lines.push("-->");
  lines.push("");
  lines.push("# rmd CLI reference");
  lines.push("");
  lines.push(
    "Every `rmd <command>` this binary dispatches, rendered from the same `COMMANDS` registry " +
      "`rmd --help` and `rmd <cmd> --help` render from (W1-T47) -- this file cannot list a " +
      "command the registry doesn't have, or drift out of sync with what actually runs (see " +
      "`test/help-registry.test.ts` for the registry<->dispatch coverage check that guarantees " +
      "that). For the fail-loud-on-bad-input / STOP-vs-PAUSE narrative, see " +
      "[`docs/control-surface.md`](control-surface.md).",
  );
  lines.push("");
  lines.push("## `rmd --help`");
  lines.push("");
  lines.push("```");
  lines.push(usage);
  lines.push("```");
  lines.push("");
  lines.push("## Commands");
  lines.push("");
  for (const spec of commands) {
    const { invocation, description } = splitUsage(spec.usage);
    lines.push(`### \`rmd ${spec.name}\``);
    lines.push("");
    lines.push("```");
    lines.push(invocation);
    lines.push("```");
    lines.push("");
    if (description) {
      lines.push(description);
      lines.push("");
    }
  }
  // Trim the trailing blank line the loop above leaves, then end with exactly one newline.
  while (lines.length > 0 && lines[lines.length - 1] === "") lines.pop();
  return lines.join("\n") + "\n";
}

function main(argv) {
  const { values } = parseArgs({
    args: argv,
    options: {
      out: { type: "string", default: DEFAULT_OUT },
      check: { type: "boolean", default: false },
    },
  });

  const fresh = renderReference(COMMANDS, USAGE);

  if (values.check) {
    let committed;
    try {
      committed = readFileSync(values.out, "utf8");
    } catch {
      console.error(
        `generate-cli-reference: ${values.out} does not exist -- run 'npm run cli-reference' to generate it.`,
      );
      process.exitCode = 1;
      return;
    }
    if (committed !== fresh) {
      const drifted = driftedCommandNames(committed, fresh);
      const named = drifted.length > 0 ? ` Drifted command(s): ${drifted.join(", ")}.` : "";
      console.error(
        `generate-cli-reference: ${values.out} is STALE -- it does not match a fresh regeneration ` +
          `from src/run-task.ts's COMMANDS registry.${named}\nRun 'npm run cli-reference' and commit the result.`,
      );
      process.exitCode = 1;
      return;
    }
    console.log(`generate-cli-reference: OK -- ${values.out} matches the current COMMANDS registry.`);
    process.exitCode = 0;
    return;
  }

  writeFileSync(values.out, fresh);
  console.log(`generate-cli-reference: wrote ${values.out} (${COMMANDS.length} command(s)).`);
  process.exitCode = 0;
}

// Only run when executed directly (`tsx scripts/generate-cli-reference.mjs ...`), never on import.
if (import.meta.url === pathToFileURL(process.argv[1] ?? "").href) {
  main(process.argv.slice(2));
}
